external_knowledge:
- 'Seeds in the fertile garden' metaphorically refers to 'active technologies'.;
- 'Sprouted' implies technologies that are 'active' and thus part of the dataset returned by the query.;
- 'Criterion scores' and 'weights of these criteria' represent the evaluation results and their respective weights.;
- 'Impact ratings' symbolize the overall score impacting the technology's growth or effectiveness.;
- 'Factors nurturing their growth' refers to the factors influencing the technology's performance or success.

sql:
SELECT criteria_name
FROM evaluation_criteria
WHERE weight > 0.5;

SELECT NULLIF(score, 0) AS score
FROM ir_scores
WHERE tech_id = 1;

SELECT *
FROM criteria_weights
WHERE weight > 0.35 AND effective_date > '2023-01-01';

SELECT tech_id, tech_name, description 
FROM technologies 
WHERE tech_id = 1;

SELECT tech_id, AVG(score) AS average_score
FROM evaluation_results
GROUP BY tech_id;

SELECT COUNT(*) AS num_tech_above_avg
FROM evaluation_results
WHERE score > (
    SELECT AVG(score)
    FROM evaluation_results
);

SELECT tech_name, description, tech_id, status
FROM technologies
WHERE tech_id NOT IN (
    SELECT tech_id
    FROM evaluation_results
);

SELECT tech_id, tech_name, POW(tech_id, 3) AS score
FROM technologies
WHERE tech_id > 10 AND category_id = 2;
